import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const DisciplineManager = () => {
  const { user } = useAuth();
  const { 
      disciplineTypes, addDisciplineType, updateDisciplineTypeStatus,
      disciplineRecords, updateDisciplineRecordStatus, deleteDisciplineRecord,
      staffList 
  } = useData();
  
  const [newType, setNewType] = useState('');

  // Determine Role
  const isOp = user.role === 'op';
  const isReg = user.role === 'reg';
  const isChief = user.role === 'chief';

  // --- LOGIC HÌNH THỨC KỶ LUẬT (TYPES) ---
  const handleAddType = (e) => {
      e.preventDefault();
      // Op đề xuất -> Pending, Reg/Chief thêm -> Active
      const status = isOp ? 'Pending' : 'Active';
      addDisciplineType({ name: newType, status, createdBy: user.username });
      setNewType('');
  };

  // --- LOGIC HỒ SƠ VI PHẠM (RECORDS) ---
  // Op/Reg/Chief đều thấy list này
  // Reg có thể "Đề xuất xóa" -> status: PendingRemoval
  // Chief có thể "Duyệt xóa" -> deleteRecord
  
  const handleRequestRemoval = (recordId) => {
      if(window.confirm('Bạn muốn đề xuất xóa vi phạm này?')) {
          updateDisciplineRecordStatus(recordId, 'PendingRemoval');
      }
  };

  const handleApproveRemoval = (recordId) => {
      if(window.confirm('Chấp thuận xóa vĩnh viễn vi phạm này?')) {
          deleteDisciplineRecord(recordId);
      }
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2 style={{ color: '#b91c1c' }}>Quản lý Kỷ luật</h2>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
          
          {/* CỘT 1: QUẢN LÝ DANH MỤC HÌNH THỨC */}
          <div style={{ background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
             <h4>1. Danh mục hình thức xử lý</h4>
             <ul style={{ listStyle: 'none', padding: 0 }}>
                {disciplineTypes.map(d => (
                    <li key={d.id} style={{ padding: '10px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between' }}>
                        <span>
                            {d.name} 
                            <span style={{ fontSize: '0.8rem', marginLeft: '10px', padding: '2px 6px', borderRadius: '4px', background: d.status==='Active'?'#ecfdf5':'#fff7ed', color: d.status==='Active'?'green':'orange' }}>
                                {d.status === 'Active' ? 'Đã duyệt' : 'Chờ duyệt'}
                            </span>
                        </span>
                        {/* Reg Admin duyệt đề xuất của Op */}
                        {isReg && d.status === 'Pending' && (
                            <div>
                                <button onClick={() => updateDisciplineTypeStatus(d.id, 'Active')} style={{color: 'green'}}>✓ Duyệt</button>
                                <button onClick={() => updateDisciplineTypeStatus(d.id, 'Rejected')} style={{color: 'red'}}>✕ Hủy</button>
                            </div>
                        )}
                    </li>
                ))}
             </ul>
             {(isOp || isReg) && (
                 <form onSubmit={handleAddType} style={{ marginTop: '10px', display: 'flex' }}>
                    <input value={newType} onChange={e => setNewType(e.target.value)} placeholder={isOp ? "Đề xuất hình thức..." : "Thêm hình thức..."} style={{ flex: 1, padding: '8px' }} />
                    <button type="submit" style={{ padding: '8px 15px' }}>{isOp ? 'Đề xuất' : 'Thêm'}</button>
                 </form>
             )}
          </div>

          {/* CỘT 2: DANH SÁCH NHÂN SỰ ĐANG BỊ KỶ LUẬT */}
          <div style={{ background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
             <h4>2. Nhân sự đang bị kỷ luật</h4>
             <table style={{ width: '100%', fontSize: '0.9rem' }}>
                <thead>
                    <tr style={{textAlign:'left'}}><th>Nhân sự</th><th>Vi phạm</th><th>Hình thức</th><th>Xử lý</th></tr>
                </thead>
                <tbody>
                    {disciplineRecords.map(rec => {
                        const staff = staffList.find(s => s.id === rec.staffId);
                        return (
                            <tr key={rec.id} style={{ borderBottom: '1px solid #eee' }}>
                                <td style={{padding:'8px'}}>{staff?.name}</td>
                                <td>{rec.violation}</td>
                                <td style={{color:'#b91c1c', fontWeight:'bold'}}>{rec.penaltyName}</td>
                                <td>
                                    {rec.status === 'Active' && isReg && (
                                        <button onClick={() => handleRequestRemoval(rec.id)} style={{fontSize:'0.75rem'}}>Đề xuất xóa</button>
                                    )}
                                    {rec.status === 'PendingRemoval' && (
                                        <span style={{color: 'orange', fontSize: '0.75rem'}}>Chờ Chief duyệt xóa</span>
                                    )}
                                    {rec.status === 'PendingRemoval' && isChief && (
                                        <button onClick={() => handleApproveRemoval(rec.id)} style={{color: 'red', fontWeight: 'bold'}}>CHẤP THUẬN XÓA</button>
                                    )}
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
             </table>
          </div>
      </div>
    </div>
  );
};

export default DisciplineManager;
